import { Injectable, HttpException, HttpStatus } from '@nestjs/common';
import { HttpService } from '@nestjs/axios';
import { ConfigService } from '@nestjs/config';
import { firstValueFrom } from 'rxjs';

@Injectable()
export class KybService {
  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
  ) {}

  async verifyBusiness(registrationNumber: string, companyType: string) {
    const apiKey = this.configService.get<string>('PREMBLY_API_KEY');
    const appId = this.configService.get<string>('PREMBLY_APP_ID');

    if (!apiKey) {
      throw new HttpException('Prembly API key not configured', HttpStatus.INTERNAL_SERVER_ERROR);
    }

    const url = 'https://api.prembly.com/identitypass/verification/cac';

    try {
      const response = await firstValueFrom(
        this.httpService.post(
          url,
          {
            rc_number: registrationNumber,
            company_type: companyType,
          },
          {
            headers: {
              'x-api-key': apiKey,
              'app-id': appId,
            },
          },
        ),
      );

      return response.data;
    } catch (error) {
      if (error.response) {
        throw new HttpException(error.response.data, error.response.status);
      }
      throw new HttpException('Failed to verify business', HttpStatus.INTERNAL_SERVER_ERROR);
    }
  }
}

