import { Controller, Post, Req, Res, Headers, HttpStatus, HttpException, RawBodyRequest } from '@nestjs/common';
import { Request, Response } from 'express';
import { ConfigService } from '@nestjs/config';
import * as crypto from 'crypto';

@Controller('webhook')
export class WebhookController {
  constructor(private readonly configService: ConfigService) {}

  @Post('prembly')
  handleWebhook(
    @Req() req: RawBodyRequest<Request>,
    @Res() res: Response,
    @Headers('x-prembly-signature') signature: string,
  ) {
    if (!signature) {
      throw new HttpException('Missing signature', HttpStatus.UNAUTHORIZED);
    }

    const secret = this.configService.get<string>('PREMBLY_WEBHOOK_SECRET') || this.configService.get<string>('PREMBLY_API_KEY');

    if (!secret) {
      throw new HttpException('Webhook secret not configured', HttpStatus.INTERNAL_SERVER_ERROR);
    }

    const payload = req.rawBody ? req.rawBody.toString('utf8') : JSON.stringify(req.body);

    const expectedSignature = crypto.createHmac('sha512', secret).update(payload).digest('hex');

    if (expectedSignature !== signature) {
      throw new HttpException('Invalid signature', HttpStatus.UNAUTHORIZED);
    }

    // Process webhook...
    console.log('Webhook payload received:', req.body);

    return res.status(HttpStatus.OK).send('Webhook received');
  }
}

